<?php
 namespace WPAICG\ContentWriter\Prompt; if (!defined('ABSPATH')) { exit; } class AIPKit_Content_Writer_Summarizer { public static function summarize(string $html_content, int $word_count = 300): string { $text = wp_strip_all_tags(strip_shortcodes($html_content)); $text = preg_replace('/\s+/', ' ', $text); if (!$text) { return ''; } return wp_trim_words($text, $word_count, '...'); } } 